<template><div class="dashboard"><section class="hero"><div><span class="eyebrow">PHARMACY OVERVIEW</span><h1>下午好，{{auth.user?.name||'药师'}}</h1><p>今日处方流转平稳，请优先处理等待时间较长的处方。</p><div class="hero-actions"><el-button type="primary" @click="$router.push('/pending')">开始发药 <el-icon><Right/></el-icon></el-button><el-button @click="$router.push('/inventory')">查看库存</el-button></div></div><div class="hero-art"><div class="pill p1"></div><div class="pill p2"></div><el-icon><FirstAidKit/></el-icon></div></section><section class="stats"><article><span class="stat-icon teal"><el-icon><DocumentChecked/></el-icon></span><div><p>待发药处方</p><strong>{{stats.pending}}</strong><small>请及时完成核对</small></div></article><article><span class="stat-icon blue"><el-icon><CircleCheck/></el-icon></span><div><p>已发药处方</p><strong>{{stats.dispensed}}</strong><small>累计发药记录</small></div></article><article><span class="stat-icon amber"><el-icon><Warning/></el-icon></span><div><p>低库存药品</p><strong>{{stats.lowStock}}</strong><small>库存少于 20</small></div></article><article><span class="stat-icon violet"><el-icon><Box/></el-icon></span><div><p>药品品种</p><strong>{{stats.medicines}}</strong><small>在库药品总数</small></div></article></section><div class="dash-grid"><section class="card queue-card"><div class="card-head"><div><span class="eyebrow">DISPENSING QUEUE</span><h2>发药队列</h2></div><el-button link type="primary" @click="$router.push('/pending')">查看全部 <el-icon><ArrowRight/></el-icon></el-button></div><div v-loading="loading"><div v-for="(p,index) in pending" :key="p.id" class="queue-item"><span class="queue-no">{{String(index+1).padStart(2,'0')}}</span><div class="patient"><strong>{{p.patientName}}</strong><small>处方号 RX{{String(p.id).padStart(6,'0')}} · {{p.doctorName}}医生</small></div><div class="drug-count">{{parseDrugs(p.drugs).length}} 种药品</div><time>{{formatTime(p.createTime)}}</time><el-button type="primary" plain size="small" @click="$router.push('/pending')">去核对</el-button></div><el-empty v-if="!pending.length&&!loading" description="暂无待发药处方" :image-size="70"/></div></section><section class="card safety-card"><div class="card-head"><div><span class="eyebrow">SAFETY CHECK</span><h2>发药核对规范</h2></div></div><div class="check-list"><div v-for="(x,i) in checks" :key="x.title"><span>{{i+1}}</span><div><strong>{{x.title}}</strong><p>{{x.desc}}</p></div><el-icon><CircleCheckFilled/></el-icon></div></div><div class="safety-tip"><el-icon><InfoFilled/></el-icon><span>确认发药后状态不可撤回，请完成四项核对。</span></div></section></div></div></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{Right,FirstAidKit,DocumentChecked,CircleCheck,Warning,Box,ArrowRight,CircleCheckFilled,InfoFilled}from'@element-plus/icons-vue';import{getMedicines,getPrescriptions}from'@/api/pharmacy';import{useAuthStore}from'@/stores/auth';import type{Drug,Prescription}from'@/types';const auth=useAuthStore(),loading=ref(false),pending=ref<Prescription[]>([]),stats=reactive({pending:0,dispensed:0,lowStock:0,medicines:0});const checks=[{title:'核对患者',desc:'姓名与处方信息一致'},{title:'核对药品',desc:'名称、规格准确无误'},{title:'核对数量',desc:'数量与处方用量一致'},{title:'用药交代',desc:'向患者说明用法用量'}];const parseDrugs=(s:string):Drug[]=>{try{return JSON.parse(s||'[]')}catch{return[]}};const formatTime=(s:string)=>new Date(s).toLocaleTimeString('zh-CN',{hour:'2-digit',minute:'2-digit'});onMounted(async()=>{loading.value=true;try{const[p,d,m]=await Promise.all([getPrescriptions('待发药',1,5),getPrescriptions('已发药',1,1),getMedicines({page:1,size:200})]);pending.value=p.data.data.content;stats.pending=p.data.data.totalElements;stats.dispensed=d.data.data.totalElements;stats.medicines=m.data.data.totalElements;stats.lowStock=m.data.data.content.filter(x=>x.stock<20).length}finally{loading.value=false}})</script>
